from dataclasses import dataclass
from decimal import Decimal

@dataclass
class Transaction:
    tx_id: str
    amount: Decimal
    currency: str

    def __post_init__(self):
        if not isinstance(self.amount, Decimal):
            raise ValueError("amount must be Decimal")
        self.amount = self.amount.quantize(Decimal("0.01"))
        if self.amount <= 0:
            raise ValueError("amount must be > 0")
        if self.currency not in {"PEN", "USD"}:
            raise ValueError("currency not allowed")

print(Transaction("T1", Decimal("10.00"), "PEN"))
for bad in [(Decimal("0"), "PEN"), (Decimal("10.00"), "EUR")]:
    try:
        Transaction("T2", bad[0], bad[1])
    except ValueError as e:
        print("reject", e)
try:
    Transaction("T3", 10.0, "PEN")
except (ValueError, TypeError) as e:
    print("reject float", e)

