from typing import Protocol

class Scorer(Protocol):
    def score(self, pair: dict) -> float: ...

class RuleScorer:
    def score(self, pair: dict) -> float:
        return 0.9 if pair.get("same_doc") else 0.1

def run(scorer: Scorer, pair: dict) -> float:
    return scorer.score(pair)

print(run(RuleScorer(), {"same_doc": True}))

